import java.util.*;

public class GreedyIntervals {

    // ── Activity Selection: max non-overlapping intervals ─────────
    // Sort by END time, greedily pick intervals that don't conflict
    static int maxNonOverlapping(int[][] intervals) {
        if (intervals.length == 0) return 0;
        // Sort by end time
        Arrays.sort(intervals, (a, b) -> a[1] - b[1]);
        int count = 1;
        int lastEnd = intervals[0][1];
        for (int i = 1; i < intervals.length; i++) {
            if (intervals[i][0] >= lastEnd) { // starts after last ends
                count++;
                lastEnd = intervals[i][1];
            }
            // else: overlaps — skip (greedy choice: keep earlier-ending one)
        }
        return count;
    }

    // ── Minimum intervals to remove to make rest non-overlapping ──
    static int minRemovalsToNonOverlap(int[][] intervals) {
        Arrays.sort(intervals, (a, b) -> a[1] - b[1]); // sort by end
        int keep = 0, lastEnd = Integer.MIN_VALUE;
        for (int[] iv : intervals) {
            if (iv[0] >= lastEnd) { keep++; lastEnd = iv[1]; }
            // overlapping intervals are implicitly removed (not counted)
        }
        return intervals.length - keep;
    }

    // ── Merge overlapping intervals ───────────────────────────────
    static int[][] mergeIntervals(int[][] intervals) {
        Arrays.sort(intervals, (a, b) -> a[0] - b[0]); // sort by START
        List<int[]> merged = new ArrayList<>();
        merged.add(intervals[0]);
        for (int i = 1; i < intervals.length; i++) {
            int[] last = merged.get(merged.size() - 1);
            if (intervals[i][0] <= last[1]) {           // overlaps
                last[1] = Math.max(last[1], intervals[i][1]); // extend end
            } else {
                merged.add(intervals[i]);                // no overlap: new interval
            }
        }
        return merged.toArray(new int[0][]);
    }

    public static void main(String[] args) {
        int[][] ivs = {{1,2},{2,3},{3,4},{1,3}};
        System.out.println("Max non-overlapping: " + maxNonOverlapping(ivs)); // 3
        System.out.println("Min removals: " + minRemovalsToNonOverlap(ivs));  // 1

        int[][] mergeInput = {{1,3},{2,6},{8,10},{15,18}};
        int[][] result = mergeIntervals(mergeInput);
        for (int[] iv : result) System.out.println(Arrays.toString(iv));
        // [1,6] [8,10] [15,18]
    }
}

public class JumpGame {

    // ── Jump Game I: Can reach last index? ────────────────────────
    // nums[i] = max jump length from position i
    static boolean canJump(int[] nums) {
        int maxReach = 0;
        for (int i = 0; i < nums.length; i++) {
            if (i > maxReach) return false; // can't reach current position
            maxReach = Math.max(maxReach, i + nums[i]);
            if (maxReach >= nums.length - 1) return true;
        }
        return true;
    }

    // ── Jump Game II: Minimum jumps to reach last index ───────────
    // Greedy: at each 'current range', find furthest reachable → jump
    static int minJumps(int[] nums) {
        int jumps = 0;
        int currentEnd = 0; // end of current jump range
        int farthest  = 0; // furthest we can reach from current range
        for (int i = 0; i < nums.length - 1; i++) {
            farthest = Math.max(farthest, i + nums[i]);
            if (i == currentEnd) {  // must jump — current range exhausted
                jumps++;
                currentEnd = farthest;
            }
        }
        return jumps;
    }

    // ── Minimum number of meeting rooms ──────────────────────────
    static int minMeetingRooms(int[][] intervals) {
        int n = intervals.length;
        int[] starts = new int[n], ends = new int[n];
        for (int i = 0; i < n; i++) {
            starts[i] = intervals[i][0];
            ends[i]   = intervals[i][1];
        }
        java.util.Arrays.sort(starts);
        java.util.Arrays.sort(ends);

        int rooms = 0, maxRooms = 0, endPtr = 0;
        for (int startPtr = 0; startPtr < n; startPtr++) {
            if (starts[startPtr] < ends[endPtr]) {
                rooms++; // new meeting starts before any ends → need extra room
            } else {
                endPtr++; // a meeting ended — reuse that room
            }
            maxRooms = Math.max(maxRooms, rooms);
        }
        return maxRooms;
    }

    public static void main(String[] args) {
        System.out.println(canJump(new int[]{2,3,1,1,4})); // true
        System.out.println(canJump(new int[]{3,2,1,0,4})); // false (stuck at 0)

        System.out.println(minJumps(new int[]{2,3,1,1,4})); // 2
        System.out.println(minJumps(new int[]{2,3,0,1,4})); // 2

        int[][] mtgs = {{0,30},{5,10},{15,20}};
        System.out.println("Meeting rooms: " + minMeetingRooms(mtgs)); // 2
    }
}

